
import React, { useState, useRef } from 'react';
//import QRCode from 'qrcode';
import jsQR from 'jsqr';
import { useNavigate } from 'react-router-dom';
const Decode = () => {

    //const [text, setText] = useState('');
    const [decodedText, setDecodedText] = useState('');
    //const canvasRef = useRef(null);
    const fileInputRef = useRef(null);

    const decodeQRCode = async () => {
      const fileInput = fileInputRef.current;
    
      // Check if a file is selected
      if (fileInput.files && fileInput.files[0]) {
        const file = fileInput.files[0];
        const reader = new FileReader();
    
        reader.onload = async (event) => {
          const imageData = event.target.result;
    
          try {
            const img = new Image();
    
            img.onload = () => {
              const canvas = document.createElement('canvas');
              const context = canvas.getContext('2d');
              canvas.width = img.width;
              canvas.height = img.height;
              context.drawImage(img, 0, 0);
              const imageData = context.getImageData(0, 0, img.width, img.height);
    
              const code = jsQR(imageData.data, imageData.width, imageData.height);
              if (code) {
                setDecodedText(code.data);
              } else {
                setDecodedText('No QR code found');
              }
            };
    
            img.src = imageData;
          } catch (error) {
            console.error('Error decoding QR code:', error);
            setDecodedText('Error decoding QR code');
          }
        };
    
        // Read file as data URL
        reader.readAsDataURL(file);
      }
    };
    const navigate= useNavigate();
      function gotogenerate(){
        navigate("/Generate")
      }
      function gotodecode(){
        navigate("/Decode")
      }
      function gotohome(){
        navigate("/")
  }
    return (
      <>
       <div className='container'>
       <div className='container1'>
    <button className='btn' onClick={gotohome}>Home</button>_
    <button className='btn' onClick={gotogenerate}>Generate</button>_
    <button className='btn' onClick={gotodecode}>Decode</button>
    </div>
     <hr/>
    <div className='container'>
     <div className='row'>
      <div className='col-md-5 card opacity p-5'>
          <input  className='inputbtn' type="file" accept="image/*" ref={fileInputRef} />
          <br></br>
          <button className='btn '  onClick={decodeQRCode}>Decode</button>
      </div>
      <div className='col-md-2'></div>
      <div className='col-md-5 card opacity p-5 '>
      
      <p className="decode">{decodedText}</p>
      </div>
        
      
       
      </div>
     
    </div>
    <br/><br/>
      <br/><br/>
      <br/><br/>
       </div>
      </>
    );
  };
export default Decode;