import React from "react";
import { useNavigate } from "react-router-dom";
function Home(){
    const navigate = useNavigate();
    function goToGenerate(){
        navigate('/Generate')
    }
    return(
       <>
       <div className="conatiner">
            <div className="bg">
                <h1 className="text-center" id="h1">Welcome to home page of Cacher</h1>
                <button onClick={goToGenerate} className="btn align-center ba" id="start">Start</button>  
            </div>
       </div>
       </>
       
    );
}
export default Home;