import React, { useState, useRef } from 'react';
import QRCode from 'qrcode';
import { useNavigate } from 'react-router-dom';
//import jsQR from 'jsqr';
const Generate = () => {
  const [text, setText] = useState('');
  //const [decodedText, setDecodedText] = useState('');
  const canvasRef = useRef(null);
 // const fileInputRef = useRef(null);

  const generateQRCode = async () => {
    try {
      const canvas = canvasRef.current;
      const qrCodeSize = 200; // Specify the desired size of the QR code image

      // Generate QR code
      await QRCode.toCanvas(canvas, text,{width:qrCodeSize,height:qrCodeSize});
    } catch (error) {
      console.error('Error generating QR code:', error);
    }
  };

  const downloadQRCode = () => {
    const canvas = canvasRef.current;
    const downloadLink = document.createElement('a');

    // Convert canvas to data URL
    const dataURL = canvas.toDataURL('image/png');

    // Set download link properties
    downloadLink.href = dataURL;
    downloadLink.download = 'qrcode.png';

    // Simulate click on the download link
    downloadLink.click();
  };
  const navigate= useNavigate();
      function gotogenerate(){
        navigate("/Generate")
      }
      function gotodecode(){
        navigate("/Decode")
      }
      function gotohome(){
        navigate("/")
  }

      
  
  return (
   
    <div className='container'>
      <div className='container1'>
          <button className='btn ' onClick={gotohome}>Home</button>_
          <button className='btn ' onClick={gotogenerate}>Generate</button>_
          <button className='btn ' onClick={gotodecode}>Decode</button>
      </div>
          <hr/>
      
      <div className='row'>
          <div className='col-md-5  card  p-5'>
              <h3 className='text-white'>Enter your data</h3>
              <textarea cols="45" rows="15" type="text" value={text} onChange={(e) => setText(e.target.value)}  placeholder="Enter text"/>
              <br/>
              <button className='btn' onClick={generateQRCode}>Generate</button>
          </div>
          <div className='col-md-2'>

          </div>
          <div className='col-md-5 card  p-5'>
              <canvas ref={canvasRef} />
              <button className='btn' id="download-btn" onClick={downloadQRCode}>Download</button>
          </div>
        </div>
        <br/><br/>
        <br/><br/>
        <br/><br/>
          
   </div>
    
  );
};

export default Generate;
